function clamp(v,a,b){return Math.max(a,Math.min(b,v));}
function ease(t){return t<.5?4*t*t*t:1-Math.pow(-2*t+2,3)/2;}
function rot(p,yaw,pitch,roll){let x=p.x,y=p.y,z=p.z;let cy=Math.cos(yaw),sy=Math.sin(yaw);let x1=x*cy+z*sy,z1=-x*sy+z*cy;let cp=Math.cos(pitch),sp=Math.sin(pitch);let y1=y*cp-z1*sp,z2=y*sp+z1*cp;let cr=Math.cos(roll),sr=Math.sin(roll);return{x:x1*cr-y1*sr,y:x1*sr+y1*cr,z:z2};}
